  beforeEach(() => {
    // Create test directory
    if (!fs.existsSync(TEST_DIR)) {
      fs.mkdirSync(TEST_DIR, { recursive: true });
    }
    // Change to test directory for isolation
    process.chdir(TEST_DIR);
    tracker = new SessionTracker();
  });

  afterEach(() => {
